import { useState, useEffect, useCallback } from "react";
import { supabase } from "../supabaseClient";
import "./PostCard.css";

export default function PostCard({ post, onDelete }) {
  const [user, setUser] = useState(null);

  const [liked, setLiked] = useState(false);
  const [likeCount, setLikeCount] = useState(0);

  const [following, setFollowing] = useState(false);

  const [comment, setComment] = useState("");
  const [comments, setComments] = useState([]);

  const [showComments, setShowComments] = useState(false);

  // ================= FUNCTIONS =================

  const fetchLikes = useCallback(async () => {
    const { data, error } = await supabase
      .from("likes")
      .select("id")
      .eq("post_id", post.id);

    if (!error) setLikeCount(data.length);
  }, [post.id]);

  const checkLike = useCallback(async (currentUser) => {
    const { data } = await supabase
      .from("likes")
      .select("id")
      .eq("user_id", currentUser.id)
      .eq("post_id", post.id);

    setLiked(data && data.length > 0);
  }, [post.id]);

  const checkFollow = useCallback(async (currentUser) => {
    const { data } = await supabase
      .from("follows")
      .select("id")
      .eq("follower_id", currentUser.id)
      .eq("following_id", post.user_id);

    setFollowing(data && data.length > 0);
  }, [post.user_id]);

  const fetchComments = useCallback(async () => {
    const { data, error } = await supabase
      .from("comments")
      .select(`*, profiles(name)`)
      .eq("post_id", post.id)
      .order("created_at", { ascending: false });

    if (!error) setComments(data || []);
  }, [post.id]);

  // ================= INIT =================

  useEffect(() => {
    const init = async () => {
      const { data, error } = await supabase.auth.getUser();

      if (error || !data?.user) return;

      const currentUser = data.user;
      setUser(currentUser);

      await Promise.all([
        fetchLikes(),
        checkLike(currentUser),
        checkFollow(currentUser),
      ]);
    };

    init();
  }, [post.id, fetchLikes, checkLike, checkFollow]);

  // ================= LIKE =================

  const handleLike = async () => {
    if (!user) return;

    if (liked) {
      await supabase
        .from("likes")
        .delete()
        .eq("user_id", user.id)
        .eq("post_id", post.id);

      setLiked(false);
      setLikeCount((prev) => prev - 1);
    } else {
      const { error } = await supabase.from("likes").insert([
        {
          user_id: user.id,
          post_id: post.id,
        },
      ]);

      if (!error) {
        setLiked(true);
        setLikeCount((prev) => prev + 1);
      }
    }
  };

  // ================= FOLLOW =================

  const handleFollow = async () => {
    if (!user || user.id === post.user_id) return;

    if (following) {
      await supabase
        .from("follows")
        .delete()
        .eq("follower_id", user.id)
        .eq("following_id", post.user_id);

      setFollowing(false);
    } else {
      await supabase.from("follows").insert([
        {
          follower_id: user.id,
          following_id: post.user_id,
        },
      ]);

      setFollowing(true);
    }
  };

  // ================= DELETE =================

  const handleDelete = async () => {
    if (!user) return;

    const confirmDelete = window.confirm("Delete this post?");
    if (!confirmDelete) return;

    const { error } = await supabase
      .from("posts")
      .delete()
      .eq("id", post.id);

    if (error) {
      alert(error.message);
    } else {
      // 🔥 instant UI update
      if (onDelete) onDelete(post.id);
    }
  };

  // ================= COMMENTS =================

  const handleComment = async () => {
    if (!user || comment.trim() === "") return;

    const { error } = await supabase.from("comments").insert([
      {
        user_id: user.id,
        post_id: post.id,
        content: comment,
      },
    ]);

    if (!error) {
      setComment("");
      fetchComments();
    }
  };

  const toggleComments = async () => {
    if (!showComments) {
      await fetchComments();
    }
    setShowComments(!showComments);
  };

  // ================= IMAGE =================

  let images = [];

  if (post.image_urls && post.image_urls.length > 0) {
    images = post.image_urls;
  } else if (post.image_url) {
    images = [post.image_url];
  }

  // ================= UI =================

  return (
    <div className="post-card">

      {/* HEADER */}
      <div className="post-header">
        <div className="user-info">
          <div className="avatar">👤</div>
          <span className="username">
            {post.profiles?.name || "User"}
          </span>
        </div>

        {/* FOLLOW */}
        {user && user.id !== post.user_id && (
          <button className="follow-btn" onClick={handleFollow}>
            {following ? "Following" : "Follow"}
          </button>
        )}

        {/* DELETE */}
        {user && user.id === post.user_id && (
          <button className="delete-btn" onClick={handleDelete}>
            Delete
          </button>
        )}
      </div>

      {/* CONTENT */}
      <div className="post-content">
        <p>{post.content}</p>
      </div>

      {/* IMAGES (HORIZONTAL SCROLL) */}
      {images.length > 0 && (
        <div className="post-image-container">
          <div className="image-scroll">
            {images.map((img, index) => (
              <img key={index} src={img} alt="post" />
            ))}
          </div>
        </div>
      )}

      {/* LIKE */}
      <div className="post-actions">
        <button className="like-btn" onClick={handleLike}>
          {liked ? "❤️" : "🤍"} {likeCount}
        </button>
      </div>

      {/* COMMENTS TOGGLE */}
      <p className="view-comments-btn" onClick={toggleComments}>
        {showComments ? "Hide comments" : "Show comments"}
      </p>

      {/* COMMENTS */}
      {showComments && (
        <>
          <div className="comments-container">
            {comments.map((c) => (
              <div key={c.id} className="comment-item">
                <span className="comment-user">
                  {c.profiles?.name || "User"}
                </span>
                : {c.content}
              </div>
            ))}
          </div>

          {/* ADD COMMENT */}
          <div className="comment-box">
            <input
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              placeholder="Write a comment..."
            />
            <button onClick={handleComment}>Post</button>
          </div>
        </>
      )}
    </div>
  );
}
